#!/usr/bin/env node
import browserslist from "browserslist";
import { browserslistToESVersion } from "./index.js";
const args = process.argv.slice(2);
if (args.includes('--help') || args.includes('-h')) {
    console.log(`
browserslist-to-es-version

Usage:
  npx browserslist-to-es-version [query]

Arguments:
  query    Optional browserslist query (default: reads from local config)

Examples:
  npx browserslist-to-es-version
  npx browserslist-to-es-version "Chrome >= 80, Firefox >= 72"
`);
    process.exit(0);
}
try {
    let browsers;
    if (args.length > 0) browsers = browserslist(args.join(' '));
    else {
        const configFile = browserslist.findConfigFile('.');
        if (!configFile) {
            console.error('Error: No browserslist configuration found.\n\nCreate a .browserslistrc file or add a "browserslist" field to package.json.\nAlternatively, provide a query as an argument:\n  npx browserslist-to-es-version "Chrome >= 80, Firefox >= 72"');
            process.exit(1);
        }
        browsers = browserslist();
    }
    const esVersion = browserslistToESVersion(browsers);
    console.log(esVersion);
} catch (error) {
    console.error('Error:', error instanceof Error ? error.message : String(error));
    process.exit(1);
}
